class Solution(object):
    def countOfPeaks(self, nums, queries):
        n = len(nums)
        # BIT for prefix sums of peak indicator array
        peak = [0] * n  # peak[i] = 1 if nums[i] is a peak
        def is_peak(i):
            return 1 if 0 < i < n-1 and nums[i] > nums[i-1] and nums[i] > nums[i+1] else 0
        for i in range(1, n-1):
            peak[i] = is_peak(i)
        bit = [0] * (n + 1)
        def update(i, delta):
            i += 1
            while i <= n:
                bit[i] += delta
                i += i & (-i)
        def query(i):
            i += 1
            s = 0
            while i > 0:
                s += bit[i]
                i -= i & (-i)
            return s
        def range_query(l, r):
            if l > r: return 0
            return query(r) - (query(l-1) if l > 0 else 0)
        for i in range(1, n-1):
            if peak[i]: update(i, 1)
        result = []
        for q in queries:
            if q[0] == 1:
                l, r = q[1], q[2]
                result.append(range_query(l+1, r-1))
            else:
                idx, val = q[1], q[2]
                nums[idx] = val
                for i in range(max(1, idx-1), min(n-1, idx+1+1)):
                    new_p = is_peak(i)
                    if peak[i] != new_p:
                        update(i, new_p - peak[i])
                        peak[i] = new_p
        return result
